import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Grid } from '@mui/material';
import response from './response.json';

interface RouteSegment {
  segment: number;
  distance: number;
  pace: string;
}

interface RunningStatsData {
  currentRun: {
    pace: string;
    distance: number;
    elevationGain: number;
  };
  routeSegmentSplits: RouteSegment[];
}

export default function Widget() {
  const { currentRun, routeSegmentSplits } = response.data as RunningStatsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2E3B4E' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              Current Run
            </Typography>
            <Typography variant="body1" sx={{ color: '#FFFFFF' }}>
              Pace: {currentRun.pace}
            </Typography>
            <Typography variant="body1" sx={{ color: '#FFFFFF' }}>
              Distance: {currentRun.distance.toFixed(1)} km
            </Typography>
            <Typography variant="body1" sx={{ color: '#FFFFFF' }}>
              Elevation Gain: {currentRun.elevationGain} m
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 1 }}>
              Route Segments
            </Typography>
            <Grid container spacing={1}>
              {routeSegmentSplits.map((segment) => (
                <Grid item xs={6} key={segment.segment}>
                  <Chip
                    label={`Segment ${segment.segment}: ${segment.distance} km @ ${segment.pace}`}
                    sx={{
                      width: '100%',
                      fontSize: '10px',
                      bgcolor: '#455A64',
                      color: '#FFFFFF',
                    }}
                  />
                </Grid>
              ))}
            </Grid>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
